// @kern-source: app:65
export function isMutatingToolCall(event: any): boolean {
  if (!event || event.type !== 'tool-call') {
    return false;
  }
  const toolKey = String(event.tool ?? '').toLowerCase();
  if (['edit', 'write', 'update', 'agonedit', 'agonwrite', 'applypatch', 'apply_patch'].includes(toolKey)) {
    return true;
  }
  if (['read', 'grep', 'search', 'glob', 'find', 'bash', 'run', 'agonbash', 'reportconfidence', 'quicknero'].includes(toolKey)) {
    return false;
  }
  if (typeof event.input !== 'string' || !event.input.trim().startsWith('{')) {
    return false;
  }
  try {
    const parsed = JSON.parse(event.input);
    return !(!(parsed.content || parsed.new_string || parsed.newString || parsed.old_string || parsed.oldString || parsed.path && (parsed.content || parsed.new_string || parsed.newString || parsed.old_string || parsed.oldString)));
  } catch (e) {
    return false;
  }
}

