// @kern-source: app:89
export const _telemetryResourceSample: any = ({ lastCpu: null, lastAt: 0 });

// @kern-source: app:91
function sampleLocalResourceVitals(): {cpuPercent:number,memPercent:number} {
  const now = Date.now();
  const current = process.cpuUsage();
  const prev = _telemetryResourceSample.lastCpu;
  const prevAt = Number(_telemetryResourceSample.lastAt ?? 0);
  _telemetryResourceSample.lastCpu = current;
  _telemetryResourceSample.lastAt = now;
  let cpuPercent = 0;
  if (prev && prevAt > 0 && now > prevAt) {
    const deltaMicros = Math.max(0, (current.user - prev.user) + (current.system - prev.system));
    const elapsedMicros = (now - prevAt) * 1000;
    const coreCount = Math.max(1, cpus().length);
    cpuPercent = Math.max(0, Math.min(100, (deltaMicros / (elapsedMicros * coreCount)) * 100));
  }
  const memPercent = Math.max(0, Math.min(100, (process.memoryUsage().rss / Math.max(1, totalmem())) * 100));
  return { cpuPercent, memPercent };
}

// @kern-source: app:110
function sampleEngineProcessVitals(engine: any, exactPid?: number|null): {cpuPercent?:number,memPercent?:number,processCount?:number,taskDetail?:string} {
  const pid = Number(exactPid ?? 0);
  if (Number.isFinite(pid) && pid > 0) {
    try {
      const result = spawnSync('ps', ['-p', String(pid), '-o', 'pid=,pcpu=,pmem=,comm=,args='], { encoding: 'utf-8', timeout: 700 });
      if (result.status !== 0 || !result.stdout.trim()) return {};
      const line = String(result.stdout).split('\n').find((entry: string) => entry.trim());
      if (!line) return {};
      const parts = line.trim().split(/\s+/);
      return {
        cpuPercent: Math.max(0, Math.min(100, Number(parts[1]) || 0)),
        memPercent: Math.max(0, Math.min(100, Number(parts[2]) || 0)),
        processCount: 1,
        taskDetail: `pid ${pid}`,
      };
    } catch {
      return {};
    }
  }
  const binary = String(engine?.binary ?? '').trim();
  if (!binary) return {};
  try {
    const result = spawnSync('ps', ['-axo', 'pid=,pcpu=,pmem=,comm=,args='], { encoding: 'utf-8', timeout: 700 });
    if (result.status !== 0 || !result.stdout) return {};
    const binaryName = binary.split('/').pop() || binary;
    const lines = String(result.stdout).split('\n').filter((line: string) => {
      const text = line.trim();
      if (!text) return false;
      if (!text.includes(binaryName) && !text.includes(binary)) return false;
      if (text.includes('ps -axo') || text.includes('rg ') || text.includes('grep ')) return false;
      return true;
    });
    let cpuPercent = 0;
    let memPercent = 0;
    for (const line of lines) {
      const parts = line.trim().split(/\s+/);
      cpuPercent += Number(parts[1]) || 0;
      memPercent += Number(parts[2]) || 0;
    }
    if (lines.length === 0) return {};
    return {
      cpuPercent: Math.max(0, Math.min(100, cpuPercent)),
      memPercent: Math.max(0, Math.min(100, memPercent)),
      processCount: lines.length,
      taskDetail: `${lines.length} process${lines.length === 1 ? '' : 'es'}`,
    };
  } catch {
    return {};
  }
}

// @kern-source: app:162
async function probeEngineVitals(registry: any, engineId: string, session?: PersistentSession|null, activePids?: Map<string,number>): Promise<Partial<EngineVitals>> {
  const started = Date.now();
  const localResources = sampleLocalResourceVitals();
  const mockTarget = String(process.env.AGON_MOCK_STALL_ENGINE ?? '').trim();
  if (mockTarget && (mockTarget === '*' || mockTarget === engineId)) {
    const stallMs = Number(process.env.AGON_MOCK_STALL_MS ?? 35000);
    await new Promise((resolve) => setTimeout(resolve, Number.isFinite(stallMs) ? stallMs : 35000));
  }
  const engine = registry.get(engineId);
  const exactPid = activePids?.get(engineId) ?? (session && session.engineId === engineId ? session.pid : null);
  const processResources = sampleEngineProcessVitals(engine, exactPid);
  const hasBinary = engine.binary ? registry.findBinary(engine) !== null : false;
  const hasApiKey = !!(engine.api && process.env[engine.api.apiKeyEnv]);
  const available = hasBinary || hasApiKey || (!engine.binary && !engine.api);
  let network: 'healthy'|'degraded'|'unreachable' = available ? 'healthy' : 'unreachable';
  let latencyMs = Date.now() - started;

  if (engine.api && hasApiKey && typeof fetch === 'function') {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 1200);
    try {
      const res = await fetch(engine.api.baseUrl, { method: 'HEAD', signal: controller.signal } as any);
      latencyMs = Date.now() - started;
      network = res.status >= 500 ? 'degraded' : 'healthy';
    } catch {
      latencyMs = Date.now() - started;
      network = 'degraded';
    } finally {
      clearTimeout(timeout);
    }
  }

  return {
    state: available ? 'idle' as any : 'offline' as any,
    latencyMs,
    network,
    cpuPercent: processResources.cpuPercent ?? localResources.cpuPercent,
    memPercent: processResources.memPercent ?? localResources.memPercent,
    task: available ? (hasBinary ? 'cli ready' : hasApiKey ? 'api reachable' : 'ready') : 'missing binary/API key',
    taskDetail: processResources.taskDetail ?? (hasBinary ? 'cli process not active' : undefined),
  };
}

// @kern-source: app:206
export function parseToolCallPayload(event: any): any {
  const rawInput = String(event?.input ?? '');
  let parsed: Record<string, unknown> = {};
  try {
    if (rawInput.trim().startsWith('{')) {
      parsed = JSON.parse(rawInput);
    }
  } catch (e) {
    parsed = {};
  }
  return { rawInput: rawInput, parsed: parsed, toolKey: String(event?.tool ?? '').toLowerCase() };
}

// @kern-source: app:217
export function formatConfidenceToolLabel(parsed: any, rawInput: string): string {
  const rawValue = parsed?.value ?? parsed?.confidence ?? parsed?.score;
  let value = Number(rawValue);
  if (!Number.isFinite(value)) {
    const text = String(rawInput ?? '');
    const match = text.match(/"value"\s*:\s*(\d{1,3}(?:\.\d+)?)/) || text.match(/(\d{1,3})\s*%/);
    if (match) {
      value = Number(match[1]);
    }
  }
  if (Number.isFinite(value)) {
    const pct = (value <= 1 && value > 0) ? Math.round(value * 100) : Math.round(value);
    if (pct >= 0 && pct <= 100) {
      const reasoning = String(parsed?.reasoning ?? parsed?.reason ?? parsed?.thought ?? '').replace(/\s+/g, ' ').trim();
      return reasoning ? `${pct}% confidence · ${reasoning}` : `${pct}% confidence`;
    }
  }
  return 'confidence';
}

// @kern-source: app:233
export function extractPatchText(rawInput: string, parsed: any): string {
  const values = [parsed?.patch, parsed?.content, parsed?.diff, parsed?.input].filter((value: unknown): value is string => typeof value === 'string' && value.trim().length > 0);
  const fromParsed = values.find((value: string) => value.includes('*** Begin Patch') || value.includes('diff --git') || value.split('\n').some((line: string) => line.startsWith('@@')));
  if (fromParsed) {
    return fromParsed;
  }
  if (rawInput.includes('*** Begin Patch') || rawInput.includes('diff --git') || rawInput.split('\n').some((line: string) => line.startsWith('@@'))) {
    return rawInput;
  }
  return values[0] ?? '';
}

// @kern-source: app:243
export function parsePatchPreview(rawInput: string, parsed: any): { files:string[]; lines:string[]; additions:number; deletions:number } {
  const patchText = extractPatchText(rawInput, parsed);
  const files: string[] = [];
  const lines: string[] = [];
  let additions = 0;
  let deletions = 0;
  const addFile = (filePath: string) => {
    const clean = filePath.trim().replace(/^["']|["']$/g, '');
    if (clean && !files.includes(clean)) files.push(clean);
  };

  for (const line of patchText.split('\n')) {
    const customFile = line.match(/^\*\*\* (?:Update|Add|Delete) File: (.+)$/);
    if (customFile) {
      addFile(customFile[1]);
      continue;
    }
    const diffFile = line.match(/^diff --git a\/(.+?) b\/(.+)$/);
    if (diffFile) {
      addFile(diffFile[2]);
      continue;
    }
    if (line.startsWith('+++ b/')) {
      addFile(line.slice('+++ b/'.length));
      continue;
    }
    if (line.startsWith('--- a/')) {
      addFile(line.slice('--- a/'.length));
      continue;
    }
    if (line.startsWith('@@')) {
      lines.push(line);
      continue;
    }
    if (line.startsWith('+') && !line.startsWith('+++')) {
      additions += 1;
      lines.push(line);
      continue;
    }
    if (line.startsWith('-') && !line.startsWith('---')) {
      deletions += 1;
      lines.push(line);
    }
  }

  return { files, lines, additions, deletions };
}

// @kern-source: app:292
export function toolPreviewWindow(lineCount: number, expanded: boolean): any {
  if (lineCount <= 0) {
    return { head: 0, tail: 0, skipped: 0 };
  }
  if (expanded) {
    return { head: lineCount, tail: 0, skipped: 0 };
  }
  const headLimit = expanded ? 10 : 3;
  const tailLimit = (expanded && lineCount > 18) ? 4 : 0;
  const showTail = tailLimit > 0 && lineCount > headLimit + tailLimit;
  const head = expanded ? Math.min(lineCount, showTail ? headLimit : lineCount) : Math.min(lineCount, headLimit);
  const tail = showTail ? tailLimit : 0;
  return { head: head, tail: tail, skipped: Math.max(0, lineCount - head - tail) };
}

// @kern-source: app:305
export function toolCallSupportsDetailView(event: any): boolean {
  if (!event || event.type !== 'tool-call') {
    return false;
  }
  const { rawInput, parsed, toolKey } = parseToolCallPayload(event);
  if (['edit', 'update', 'write', 'agonedit', 'agonwrite', 'applypatch', 'apply_patch'].includes(toolKey)) {
    return true;
  }
  const outputText = String(event.output ?? '');
  const outputLines = outputText ? outputText.split('\n').length : 0;
  if (toolKey === 'bash' || toolKey === 'run' || toolKey === 'agonbash') {
    const command = String((parsed.command as string) || rawInput || '');
    return command.split('\n').length > 3 || outputLines > 12 || outputText.length > 500;
  }
  if (toolKey === 'read') {
    return outputLines > 12 || outputText.length > 500;
  }
  if (toolKey === 'grep' || toolKey === 'search' || toolKey === 'glob' || toolKey === 'find') {
    return outputLines > 10 || outputText.length > 400;
  }
  return rawInput.length > 160 || outputText.length > 400;
}

