export const _pauseState: { value: PauseState | null } = { value: null };

// @kern-source: app:688
export function createInitialRegistry(): EngineRegistry {
  const reg = new EngineRegistry();
  reg.load(resolveBuiltinEnginesDir());
  return reg;
}

// @kern-source: app:694
export function drainStdinBuffer(): void {
  if (!process.stdin.isTTY || typeof process.stdin.read !== 'function') return;
  let chunk: string | Buffer | null;
  do {
    chunk = process.stdin.read();
  } while (chunk !== null);
}

// @kern-source: app:703
export function maxScrollOffsetForRowCount(rowCount: number, rowBudget: number): number {
  return Math.max(0, rowCount - Math.max(1, rowBudget));
}

// @kern-source: app:705
export function nextWheelAnimationStep(pending: number): {step:number,remaining:number} {
  if (!Number.isFinite(pending) || pending === 0) {
    return { step: 0, remaining: 0 };
  }
  const direction = (pending > 0) ? 1 : (-1);
  const magnitude = Math.abs(pending);
  const stepSize = (magnitude >= 16) ? 6 : ((magnitude >= 10) ? 5 : ((magnitude >= 6) ? 4 : ((magnitude >= 3) ? 2 : 1)));
  const step = direction * Math.min(stepSize, magnitude);
  return { step: step, remaining: pending - step };
}

// @kern-source: app:715
export function clampNumber(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

// @kern-source: app:717
export function charDisplayWidth(char: string): number {
  if (!char) {
    return 0;
  }
  const codePoint = char.codePointAt(0) ?? 0;
  if (codePoint === 0) {
    return 0;
  }
  if (codePoint < 32 || codePoint >= 0x7f && codePoint < 0xa0) {
    return 0;
  }
  if (codePoint >= 0x0300 && codePoint <= 0x036f || codePoint >= 0x1ab0 && codePoint <= 0x1aff || codePoint >= 0x1dc0 && codePoint <= 0x1dff || codePoint >= 0x20d0 && codePoint <= 0x20ff || codePoint >= 0xfe20 && codePoint <= 0xfe2f) {
    return 0;
  }
  if (codePoint === 0x2329 || codePoint === 0x232a || codePoint >= 0x1100 && codePoint <= 0x115f || codePoint >= 0x2e80 && codePoint <= 0xa4cf && codePoint !== 0x303f || codePoint >= 0xac00 && codePoint <= 0xd7a3 || codePoint >= 0xf900 && codePoint <= 0xfaff || codePoint >= 0xfe10 && codePoint <= 0xfe19 || codePoint >= 0xfe30 && codePoint <= 0xfe6f || codePoint >= 0xff00 && codePoint <= 0xff60 || codePoint >= 0xffe0 && codePoint <= 0xffe6 || codePoint >= 0x1f300 && codePoint <= 0x1f64f || codePoint >= 0x1f900 && codePoint <= 0x1f9ff || codePoint >= 0x20000 && codePoint <= 0x3fffd) {
    return 2;
  }
  return 1;
}

// @kern-source: app:732
export function stringDisplayWidth(text: string): number {
  let width = 0;
  for (const char of Array.from(String(text ?? ''))) {
    width += charDisplayWidth(char);
  }
  return width;
}

// @kern-source: app:739
export function displayColumnToStringIndex(text: string, targetColumn: number): number {
  const value = String(text ?? '');
  if (!Number.isFinite(targetColumn) || targetColumn <= 0) {
    return 0;
  }
  let displayColumn = 0;
  let stringIndex = 0;
  for (const char of Array.from(value)) {
    const width = charDisplayWidth(char);
    const nextDisplayColumn = displayColumn + width;
    if (targetColumn < nextDisplayColumn) {
      return stringIndex;
    }
    stringIndex += char.length;
    if (targetColumn === nextDisplayColumn) {
      return stringIndex;
    }
    displayColumn = nextDisplayColumn;
  }
  return value.length;
}

// @kern-source: app:757
export function normalizeRowSelection(anchor: number|null, focus: number|null): {start:number,end:number}|null {
  if (anchor === null || focus === null) {
    return null;
  }
  return { start: Math.min(anchor, focus), end: Math.max(anchor, focus) };
}

// @kern-source: app:763
export function normalizeTextSelection(anchorRow: number|null, anchorCol: number|null, focusRow: number|null, focusCol: number|null): {startRow:number,startCol:number,endRow:number,endCol:number}|null {
  if (anchorRow === null || anchorCol === null || focusRow === null || focusCol === null) {
    return null;
  }
  if (anchorRow < focusRow) {
    return { startRow: anchorRow, startCol: anchorCol, endRow: focusRow, endCol: focusCol };
  }
  if (anchorRow > focusRow) {
    return { startRow: focusRow, startCol: focusCol, endRow: anchorRow, endCol: anchorCol };
  }
  if (anchorCol <= focusCol) {
    return { startRow: anchorRow, startCol: anchorCol, endRow: focusRow, endCol: focusCol };
  }
  return { startRow: focusRow, startCol: focusCol, endRow: anchorRow, endCol: anchorCol };
}

// @kern-source: app:775
export function richLineToPlainText(line: any): string {
  if (!line) {
    return '';
  }
  if (line.kind === 'blank') {
    return '';
  }
  if (line.kind === 'hr') {
    return '─'.repeat(40);
  }
  const spanText = Array.isArray(line.spans) ? line.spans.map((span: any) => `${span.text ?? ''}${span?.style?.linkUrl ? ` (${span.style.linkUrl})` : ''}`).join('') : '';
  const indent = (line.indent > 0) ? '  '.repeat(line.indent) : '';
  if (line.kind === 'h1') {
    return `${indent}# ${spanText}`;
  }
  if (line.kind === 'h2') {
    return `${indent}## ${spanText}`;
  }
  if (line.kind === 'h3') {
    return `${indent}### ${spanText}`;
  }
  if (line.kind === 'blockquote') {
    return `${indent}| ${spanText}`;
  }
  const marker = line.marker ?? '';
  const listIndent = ((line.kind === 'bullet' || line.kind === 'ordered') && !indent) ? ' ' : '';
  return `${indent}${listIndent}${marker}${spanText}`;
}

// @kern-source: app:797
export function transcriptRowToPlainText(row: any): string {
  if (!row) {
    return '';
  }
  if (row.kind === 'spacer') {
    return '';
  }
  if (row.kind === 'gradient') {
    return String(row.text ?? '');
  }
  if (row.kind === 'rich') {
    return richLineToPlainText(row.richLine);
  }
  if (row.kind === 'segments') {
    return Array.isArray(row.segments) ? row.segments.map((segment: any) => segment?.text ?? '').join('') : '';
  }
  const prefix = String(row.prefixText ?? '');
  const text = String(row.text ?? '');
  return `${prefix}${text}`;
}

// @kern-source: app:813
export function transcriptRowTextStartColumn(row: any): number {
  const paddingLeft = Math.max(0, Number(row?.paddingLeft ?? 0));
  const borderColumns = row?.borderColor ? 2 : 0;
  return paddingLeft + borderColumns + 2;
}

// @kern-source: app:819
export function resolveTranscriptColumnFromMouse(mouseX: number, row: any): number {
  const text = transcriptRowToPlainText(row);
  const startColumn = transcriptRowTextStartColumn(row);
  if (!Number.isFinite(mouseX) || !text) {
    return 0;
  }
  const targetColumn = clampNumber(mouseX - startColumn, 0, stringDisplayWidth(text));
  return displayColumnToStringIndex(text, targetColumn);
}

// @kern-source: app:828
export function transcriptRowsToPlainText(rows: any[], anchorRow: number|null, anchorCol: number|null, focusRow: number|null, focusCol: number|null): string {
  const range = normalizeTextSelection(anchorRow, anchorCol, focusRow, focusCol);
  if (!range) return '';
  const lines: string[] = [];
  for (let rowIndex = range.startRow; rowIndex <= range.endRow; rowIndex += 1) {
    const row = rows[rowIndex];
    const text = transcriptRowToPlainText(row);
    if (rowIndex === range.startRow && rowIndex === range.endRow) {
      lines.push(text.slice(range.startCol, range.endCol));
      continue;
    }
    if (rowIndex === range.startRow) {
      lines.push(text.slice(range.startCol));
      continue;
    }
    if (rowIndex === range.endRow) {
      lines.push(text.slice(0, range.endCol));
      continue;
    }
    lines.push(text);
  }
  return lines.join('\n').replace(/\n{3,}/g, '\n\n').trimEnd();
}

// @kern-source: app:853
export function resolveTranscriptRowFromMouse(mouseY: number, viewportTopLine: number, firstVisibleRow: number, visibleRowCount: number): number|null {
  if (visibleRowCount <= 0) {
    return null;
  }
  const offset = mouseY - viewportTopLine;
  if (!Number.isFinite(offset)) {
    return null;
  }
  const clamped = clampNumber(offset, 0, visibleRowCount - 1);
  return firstVisibleRow + clamped;
}

// @kern-source: app:863
export function estimateVisibleBlockBudget(rows: number, mode: string, overlayReservedRows: number): number {
  // Chat mode keeps 7 rows for the composer/status chrome at minimum:
  // margin + bordered composer (3) + Cesar strip + two-line status bar.
  // Using 6 makes the startup dashboard overflow by one line.
  const reservedRows = (mode === 'chat') ? 7 : 8 + Math.max(0, overlayReservedRows);
  return Math.max(1, rows - reservedRows);
}

// @kern-source: app:871
export function estimateWrappedRowCount(text: string, wrapWidth: number): number {
  const safeWidth = Math.max(1, wrapWidth);
  const lines = String(text ?? '').split('\n');
  let rowCount = 0;
  for (const line of lines) {
    rowCount += Math.max(1, Math.ceil(stringDisplayWidth(line) / safeWidth));
  }
  return Math.max(1, rowCount);
}

/**
 * Reserve extra transcript rows when the bottom composer is showing a multi-line question or permission card, so short terminals do not clip the actionable keys.
 */
// @kern-source: app:880
export function estimateQuestionReservedRows(questionState: any, termWidth: number): number {
  if (!questionState) return 0;
  const safeWidth = Math.max(24, termWidth - 12);
  const prompt = String(questionState.prompt ?? '').trim();
  const promptRows = estimateWrappedRowCount(prompt, safeWidth);
  const hasChoices = Array.isArray(questionState.choices) && questionState.choices.length > 0;
  if (questionState.kind === 'permission') {
    const command = String(questionState.command ?? '').trim();
    const summary = String(questionState.reason ?? questionState.description ?? '').trim();
    const commandIsLong = command.includes('\n') || command.length > safeWidth;
    const summaryIsLong = summary.length > safeWidth;
    return commandIsLong || summaryIsLong ? 4 : 3;
  }
  if (hasChoices) {
    const inlineChoiceWidth = questionState.choices.reduce((sum: number, choice: any, index: number) => {
      const key = String(choice?.key ?? '').toUpperCase();
      const label = String(choice?.label ?? '').trim();
      return sum + stringDisplayWidth(`[${key}] ${label}`.trim()) + (index > 0 ? 2 : 0);
    }, 0);
    if (questionState.choices.length <= 3 && inlineChoiceWidth <= safeWidth) {
      return promptRows + 1;
    }
    const choiceRows = questionState.choices.reduce((sum: number, choice: any) => {
      const key = String(choice?.key ?? '').toUpperCase();
      const label = String(choice?.label ?? '').trim();
      return sum + estimateWrappedRowCount(`[${key}] ${label}`.trim(), safeWidth);
    }, 0);
    return promptRows + Math.max(1, choiceRows);
  }
  return promptRows + 1;
}

/**
 * Reserve extra rows above the base composer/status chrome for stacked prompt cards, queued-input badges, and chat spinner rows.
 */
// @kern-source: app:914
export function estimateBottomChromeExtraRows(mode: string, questionState: any, termWidth: number, pendingImageCount: number, inputQueueCount: number, hasLiveSpinner: boolean): number {
  let extraRows = 0;
  if (pendingImageCount > 0) {
    extraRows += 1;
  }
  if (inputQueueCount > 0) {
    extraRows += 1;
  }
  if (mode === 'chat' && hasLiveSpinner && !questionState) {
    extraRows += 1;
  }
  extraRows += estimateQuestionReservedRows(questionState, termWidth);
  return extraRows;
}

// @kern-source: app:927
function summarizeBtwTranscriptEvent(event: any): string|null {
  if (!event || typeof event !== 'object') return null;
  switch (event.type) {
    case 'user-message':
      return `User: ${String(event.content ?? '').slice(0, 500)}`;
    case 'engine-block':
      return `${String(event.engineId ?? 'engine')}: ${String(event.content ?? '').slice(0, 700)}`;
    case 'info':
    case 'warning':
    case 'error':
    case 'success':
      return `${event.type}: ${String(event.message ?? '').slice(0, 350)}`;
    case 'header':
      return `Section: ${String(event.title ?? '').slice(0, 250)}`;
    case 'tool-call':
      return `Tool: ${String(event.tool ?? '').slice(0, 80)} ${String(event.input ?? '').slice(0, 350)}`;
    default:
      return null;
  }
}

// @kern-source: app:949
export function buildDashboardBlock(enabledOverride: string[]|null): OutputBlock {
  const registry = createInitialRegistry();
  const available = registry.availableIds();
  const config = loadConfig();
  const ratings = getRatings();
  const enabled = enabledOverride ?? registry.activeIds(config);
  const defaultEngine = enabled.includes(config.forgeFixedStarter) ? config.forgeFixedStarter : enabled[0] ?? 'none';
  const activeWs = getActiveWorkspace();
  const totalMatches = Object.values(ratings.global).reduce((sum: number, r: any) => sum + r.wins + r.losses, 0);
  const sorted = Object.entries(ratings.global)
    .map(([id, r]: any) => [id, { rating: Math.round(r.mu - 2 * r.phi) }] as const)
    .sort(([, a], [, b]) => b.rating - a.rating);
  let runCount = 0;
  try { runCount = readdirSync(RUNS_DIR).filter((f: string) => f.endsWith('.json')).length; } catch { /* runs dir missing — first run */ }

  return {
    id: 0,
    event: {
      type: 'dashboard' as const,
      available,
      enabled,
      defaultEngine,
      eloTop: sorted.length > 0 ? { id: sorted[0][0], rating: (sorted[0][1] as any).rating } : undefined,
      totalForges: Math.floor(totalMatches / 2),
      workspace: activeWs ? { name: activeWs.name, path: activeWs.path, isKern: activeWs.isKern } : undefined,
      runCount,
    },
  };
}

// @kern-source: app:980
export function estimatePinnedLiveRows(mode: string, hasStream: boolean, hasProgress: boolean, agentCount: number, toolStreamCount?: number): number {
  const streamRows = hasStream ? ((mode === 'chat') ? 3 : 6) : 0;
  const progressRows = hasProgress ? ((mode === 'chat') ? 3 : 5) : 0;
  const agentRows = (agentCount > 0) ? Math.min(18, agentCount * 7) : 0;
  const toolRows = (toolStreamCount && toolStreamCount > 0) ? Math.min(10, 1 + toolStreamCount * 2) : 0;
  return streamRows + progressRows + agentRows + toolRows;
}

// @kern-source: app:988
export function estimateWrappedRows(text: string, width: number): number {
  const safeWidth = Math.max(1, width);
  if (!text) return 0;
  return text.split('\n').reduce((total: number, rawLine: string) => {
    const line = rawLine.replace(/\u001b\[[0-9;]*m/g, '').replace(/\t/g, '    ');
    return total + Math.max(1, Math.ceil(Math.max(1, line.length) / safeWidth));
  }, 0);
}

// @kern-source: app:998
export function estimateToolCallRows(event: any, toolOutputExpanded: boolean, codeWidth: number): number {
  if (!event || event.type !== 'tool-call') {
    return 0;
  }
  if (!event.input && !event.output && (event.tool === 'Delegate' || event.tool === 'delegate')) {
    return 0;
  }
  const { rawInput, parsed, toolKey } = parseToolCallPayload(event);
  const collapsed = !toolOutputExpanded;
  if (collapsed && !['edit', 'write', 'update', 'agonedit', 'agonwrite', 'applypatch', 'apply_patch'].includes(toolKey)) {
    return 1;
  }
  if (toolKey === 'bash' || toolKey === 'run' || toolKey === 'agonbash') {
    const cmd = (parsed.command as string) || rawInput || '';
    const cmdLineCount = cmd ? cmd.split('\n').length : 0;
    let rows = 1;
    if (cmdLineCount > 0) {
      const overflowRow = (cmdLineCount > 3) ? 1 : 0;
      const cmdRows = collapsed ? (Math.min(3, cmdLineCount) + overflowRow + 1) : (cmdLineCount + 1);
      rows += cmdRows;
    }
    if (event.output && event.status !== 'running') {
      const outputLineCount = event.output.split('\n').length;
      if (!collapsed) {
        return rows + 1 + outputLineCount;
      }
      const maxHead = (outputLineCount > 80) ? 30 : 50;
      const tailCount = 5;
      const showTail = outputLineCount > maxHead + tailCount;
      rows += 1 + Math.min(outputLineCount, maxHead);
      if (showTail) {
        rows += 1 + tailCount;
      }
    }
    return rows;
  }
  if (toolKey === 'edit' || toolKey === 'update' || toolKey === 'agonedit') {
    const oldStr = (parsed.old_string as string) || (parsed.oldString as string) || '';
    const newStr = (parsed.new_string as string) || (parsed.newString as string) || '';
    const oldLines = oldStr ? oldStr.split('\n') : [];
    const newLines = newStr ? newStr.split('\n') : [];
    const oldWindow = toolPreviewWindow(oldLines.length, !collapsed);
    const newWindow = toolPreviewWindow(newLines.length, !collapsed);
    return 1 + oldWindow.head + oldWindow.tail + (oldWindow.skipped > 0) ? 1 : 0 + newWindow.head + newWindow.tail + (newWindow.skipped > 0) ? 1 : 0;
  }
  if (toolKey === 'write' || toolKey === 'agonwrite') {
    const content = (parsed.content as string) || '';
    const lines = content ? content.split('\n') : [];
    const window = toolPreviewWindow(lines.length, !collapsed);
    return 1 + window.head + window.tail + (window.skipped > 0) ? 1 : 0;
  }
  if (toolKey === 'applypatch' || toolKey === 'apply_patch') {
    const patch = parsePatchPreview(rawInput, parsed);
    const window = toolPreviewWindow(patch.lines.length, !collapsed);
    return 1 + window.head + window.tail + (window.skipped > 0) ? 1 : 0;
  }
  if (toolKey === 'read') {
    if (collapsed) {
      return 1;
    }
    const lineCount = event.output ? String(event.output).split('\n').length : 0;
    return 1 + lineCount;
  }
  if (toolKey === 'grep' || toolKey === 'search' || toolKey === 'glob' || toolKey === 'find') {
    if (collapsed) {
      return 1;
    }
    const lineCount = event.output ? String(event.output).split('\n').filter((line: string) => line.trim()).length : 0;
    return 1 + lineCount;
  }
  let rows = 1;
  if (rawInput) {
    rows += Math.min(3, estimateWrappedRows(rawInput, codeWidth));
  }
  if (event.output && event.status === 'done') {
    rows += 1 + Math.min(6, estimateWrappedRows(event.output, codeWidth));
  }
  return rows;
}

// @kern-source: app:1064
export function estimateOutputEventRows(event: OutputEvent, mode: string, toolOutputExpanded: boolean, thinkingExpanded: boolean): number {
  const proseWidth = contentWidth(4);
  const chatWidth = contentWidth(2);
  const engineWidth = contentWidth(8);
  const codeWidth = contentWidth(10);

  switch (event.type) {
    case 'text':
      return Math.max(1, estimateWrappedRows(event.content, proseWidth));
    case 'user-message':
      return Math.max(1, estimateWrappedRows(event.content, proseWidth));
    case 'engine-block':
      return mode === 'chat'
        ? 2 + estimateWrappedRows(cleanEngineOutput(event.content), chatWidth)
        : 4 + estimateWrappedRows(cleanEngineOutput(event.content), engineWidth);
    case 'separator':
      return 1;
    case 'header':
      return 2;
    case 'success':
    case 'warning':
    case 'info':
      return Math.max(1, estimateWrappedRows(event.message, proseWidth));
    case 'error': {
      const errLines = event.message.split('\n');
      if (errLines.length <= 1) return 1;
      return Math.min(7, errLines.length + 1);
    }
    case 'permission-ask': {
      const commandRows = Math.min(6, String((event as any).command ?? '').split('\n').length);
      const descriptionRows = (event as any).description ? 2 : 0;
      return 6 + commandRows + descriptionRows;
    }
    case 'thinking-chunk':
      if (thinkingExpanded === false) return 0;
      return Math.max(1, String(event.chunk ?? '').split('\n').filter((line: string) => line.trim()).length);
    case 'streaming-chunk': {
      const chunkText = String(event.chunk ?? '');
      const isThinking = /^~?\d{1,3}%\s/.test(chunkText.trim());
      if (isThinking && thinkingExpanded === false) return 0;
      return Math.max(1, estimateWrappedRows(chunkText, proseWidth));
    }
    case 'kern-draft':
      return 4 + estimateWrappedRows(cleanEngineOutput(event.content), engineWidth);
    case 'debate-round':
      return 4 + estimateWrappedRows(cleanEngineOutput(event.argument), engineWidth);
    case 'verdict':
      return Math.max(1, estimateWrappedRows(cleanEngineOutput(event.summary), proseWidth));
    case 'scoreboard':
      return 3 + event.metrics.length + (event.winner ? 1 : 0);
    case 'plan':
      return 4 + event.plan.steps.length + (event.plan.state === 'draft' ? 1 : 0);
    case 'plan-list':
      return Math.max(1, event.plans.length);
    case 'plan-proposal':
      return Math.max(4, estimateWrappedRows(String((event as any).markdown ?? ''), proseWidth));
    case 'plan-execution':
      return 6;
    case 'table':
      return 2 + event.rows.length;
    case 'tool-call':
      return estimateToolCallRows(event as any, toolOutputExpanded, codeWidth);
    case 'response-meta':
      return 1;
    case 'cesar-recap': {
      const commandRows = Math.min(5, Array.isArray((event as any).commands) ? (event as any).commands.length : 0);
      const fileRows = Array.isArray((event as any).files) && (event as any).files.length > 0 ? 1 : 0;
      const checkpointRows = Array.isArray((event as any).checkpoints) && (event as any).checkpoints.length > 0 ? 1 : 0;
      const diffFiles = Array.isArray((event as any).diffPreview?.files) ? (event as any).diffPreview.files : [];
      const diffRows = diffFiles.reduce((total: number, file: any) => total + 1 + Math.min(6, Array.isArray(file.lines) ? file.lines.length : 0) + (Number(file.omitted ?? 0) > 0 ? 1 : 0), 0);
      const warningRows = Math.min(3, Array.isArray((event as any).warnings) ? (event as any).warnings.length : 0);
      const reasoningRows = (event as any).confidenceReasoning ? 1 : 0;
      return 3 + commandRows + fileRows + checkpointRows + diffRows + warningRows + reasoningRows;
    }
    case 'file-changes':
      return 1 + (((event as any).files as any[])?.length ?? 0);
    case 'dashboard':
      return 17;
    case 'agent-step-start':
    case 'agent-step-end':
    case 'agent-turn-summary':
    case 'agent-budget-warning':
    case 'engine-switch':
    case 'shadow-active':
    case 'agent-routing':
    case 'agent-team-start':
    case 'agent-team-complete':
      return 1;
    case 'spinner-start':
    case 'spinner-stop':
    case 'spinner-update':
    case 'progress-update':
    case 'progress-clear':
    case 'confidence-update':
    case 'streaming-end':
    case 'clear':
    case 'question':
    case 'patch-review':
      return 0;
    default:
      return 1;
  }
}

// @kern-source: app:1169
export function buildDisplayItems(blocks: OutputBlock[], toolOutputExpanded: boolean): OutputBlock[] {
  // Keep collapse as a per-block display concern, not a synthetic grouped
  // scroll unit. Grouped tool summaries make wheel scrolling jump because
  // one collapsed row can stand in for many logical rows.
  return blocks;
}

// @kern-source: app:1176
export function isToolCallLikeBlock(block: OutputBlock): boolean {
  const type = (block?.event as any)?.type;
  return type === 'tool-call' || type === 'tool-call-group';
}

/**
 * Merge adjacent tool-call and tool-call-group blocks into one group so native/live renderers do not show repeated collapsed tool summaries.
 */
// @kern-source: app:1181
export function coalesceToolCallBlocks(blocks: OutputBlock[]): OutputBlock[] {
  if (!Array.isArray(blocks) || blocks.length === 0) return [];
  const out: OutputBlock[] = [];
  let index = 0;

  const appendToolChildren = (block: OutputBlock, children: OutputBlock[]) => {
    const event = block.event as any;
    if (event?.type === 'tool-call') {
      children.push(block);
      return;
    }
    if (event?.type === 'tool-call-group' && Array.isArray(event.blocks)) {
      for (const child of event.blocks) {
        if (child?.event?.type === 'tool-call') children.push(child);
      }
    }
  };

  while (index < blocks.length) {
    const block = blocks[index];
    if (!isToolCallLikeBlock(block)) {
      out.push(block);
      index += 1;
      continue;
    }

    const children: OutputBlock[] = [];
    const first = block;
    while (index < blocks.length && isToolCallLikeBlock(blocks[index])) {
      appendToolChildren(blocks[index], children);
      index += 1;
    }

    if (children.length === 1 && (first.event as any)?.type === 'tool-call') {
      out.push(first);
    } else {
      out.push({ id: first.id, event: { type: 'tool-call-group', blocks: children } as any });
    }
  }

  return out;
}

/**
 * Choose the native Static archive count. When tools are expanded, keep the latest tool-call island live because Ink Static cannot repaint already-sealed collapsed tool summaries.
 */
// @kern-source: app:1226
export function effectiveNativeArchiveBlockCount(blocks: OutputBlock[], baseArchiveCount: number, targetArchiveCount: number, toolOutputExpanded: boolean): number {
  if (!Array.isArray(blocks) || blocks.length === 0) return 0;

  if (toolOutputExpanded) {
    let latestToolIndex = -1;
    for (let index = blocks.length - 1; index >= 0; index -= 1) {
      if (isToolCallLikeBlock(blocks[index])) {
        latestToolIndex = index;
        break;
      }
    }
    if (latestToolIndex >= 0) {
      let islandStart = latestToolIndex;
      while (islandStart > 0 && isToolCallLikeBlock(blocks[islandStart - 1])) {
        islandStart -= 1;
      }
      return islandStart;
    }
  }

  let count = Math.max(0, Math.min(blocks.length, Math.max(baseArchiveCount, targetArchiveCount)));
  while (
    count > 0
    && count < blocks.length
    && isToolCallLikeBlock(blocks[count - 1])
    && isToolCallLikeBlock(blocks[count])
  ) {
    count -= 1;
  }
  return count;
}

// @kern-source: app:1260
export function estimateDisplayItemRows(item: OutputBlock, mode: string, toolOutputExpanded: boolean, thinkingExpanded: boolean): number {
  return estimateOutputEventRows(item.event, mode, toolOutputExpanded, thinkingExpanded);
}

// @kern-source: app:1262
export function historyBlocksForTranscript(blocks: OutputBlock[]): OutputBlock[] {
  if (blocks.length === 1 && blocks[0]?.event?.type === 'dashboard') {
    return [];
  }
  return blocks;
}

/**
 * Native transcript history. While idle, the startup dashboard is live chrome. Once the first real transcript row exists, keep the dashboard as the first chat-history block so the AGON header scrolls with the conversation instead of disappearing.
 */
// @kern-source: app:1268
export function nativeTranscriptBlocksForStatic(blocks: OutputBlock[]): OutputBlock[] {
  if (blocks.length === 1 && blocks[0]?.event?.type === 'dashboard') {
    return [];
  }
  return blocks;
}

/**
 * Choose how many native transcript blocks are sealed into Static. The remaining tail stays live so recent rows can rerender while older rows remain in terminal scrollback.
 */
// @kern-source: app:1275
export function nativeArchiveBlockCount(blocks: OutputBlock[], mode: string, rowBudget: number, toolOutputExpanded: boolean, thinkingExpanded: boolean): number {
  if (!Array.isArray(blocks) || blocks.length === 0) return 0;

  const safeBudget = Math.max(1, Math.floor(Number(rowBudget) || 1));
  const maxLiveBlocks = 80;
  let rows = 0;
  let liveStart = blocks.length;

  for (let index = blocks.length - 1; index >= 0; index -= 1) {
    const block = blocks[index];
    const event = block?.event as OutputEvent;
    const estimatedRows = Math.max(1, estimateOutputEventRows(event, mode, toolOutputExpanded, thinkingExpanded));
    const liveCountWithBlock = blocks.length - index;

    if (estimatedRows > safeBudget && rows === 0) {
      liveStart = index + 1;
      break;
    }

    if (rows > 0 && (rows + estimatedRows > safeBudget || liveCountWithBlock > maxLiveBlocks)) {
      break;
    }

    rows += estimatedRows;
    liveStart = index;
  }

  return Math.max(0, Math.min(blocks.length, liveStart));
}

/**
 * Detect same-turn duplicate completed engine output. A new user-message resets the guard so an intentional repeat request can still show identical text.
 */
// @kern-source: app:1307
export function isDuplicateEngineBlock(blocks: OutputBlock[], event: any): boolean {
  if (!event || event.type !== 'engine-block') return false;
  const content = cleanEngineOutput(String(event.content ?? '')).trim();
  if (!content) return false;
  const engineId = String(event.engineId ?? '');
  for (let index = blocks.length - 1; index >= 0 && index >= blocks.length - 24; index -= 1) {
    const prev = blocks[index]?.event as any;
    if (!prev) continue;
    if (prev.type === 'user-message') return false;
    if (prev.type !== 'engine-block') continue;
    const prevContent = cleanEngineOutput(String(prev.content ?? '')).trim();
    if (String(prev.engineId ?? '') === engineId && prevContent === content) {
      return true;
    }
  }
  return false;
}

/**
 * Append a transcript block with cap/archive handling while suppressing accidental duplicate engine output.
 */
// @kern-source: app:1327
export function appendTranscriptBlock(blocks: OutputBlock[], event: any, archivePath: string): OutputBlock[] {
  if (isDuplicateEngineBlock(blocks, event)) {
    return blocks;
  }
  return appendBlockWithCap(blocks, { id: Date.now() + Math.random(), event: event }, archivePath);
}

// @kern-source: app:1334
export function normalizeTerminalMode(value: any): 'native'|'fullscreen' {
  return value === 'fullscreen' ? 'fullscreen' : 'native';
}

// @kern-source: app:1336
export function fileRailWidthForTerminal(termWidth: number, expanded: boolean): number {
  const safeWidth = Math.max(40, Math.floor(Number(termWidth) || 100));
  if (expanded) {
    return Math.max(36, Math.min(84, Math.floor(safeWidth * 0.35)));
  }
  return Math.max(28, Math.min(42, Math.floor(safeWidth * 0.22)));
}

// @kern-source: app:1343
export function fileRailMaxRowsForTerminal(termHeight: number, terminalMode: string, expanded: boolean): number {
  const safeHeight = Math.max(8, Math.floor(Number(termHeight) || 24));
  if (terminalMode === 'native') {
    if (expanded) {
      return Math.max(8, Math.min(36, safeHeight - 4));
    }
    return Math.max(5, Math.min(14, safeHeight - 8));
  }
  if (expanded) {
    return Math.max(12, safeHeight - 4);
  }
  return Math.max(6, Math.min(12, 10));
}

/**
 * Pure terminal replay harness: summarizes the layout-sensitive parts of the REPL for fixed viewport sizes so unit tests can catch native/fullscreen regressions without launching an interactive TTY.
 */
// @kern-source: app:1354
export function buildTerminalReplaySnapshot(blocks: OutputBlock[], opts: any): {terminalMode:'native'|'fullscreen'; mode:string; termWidth:number; termHeight:number; visibleBudget:number; transcriptRowCount:number; staticBlockCount:number; liveBlockCount:number; fileRailWidth:number; fileRailRows:number; headerRows:number; lowerChromeRows:number} {
  const terminalMode = normalizeTerminalMode(opts?.terminalMode);
  const mode = String(opts?.mode ?? 'chat');
  const termWidth = Math.max(40, Math.floor(Number(opts?.termWidth) || 100));
  const termHeight = Math.max(8, Math.floor(Number(opts?.termHeight) || 24));
  const toolOutputExpanded = opts?.toolOutputExpanded !== false;
  const thinkingExpanded = opts?.thinkingExpanded !== false;
  const questionState = opts?.questionState ?? null;
  const pendingImageCount = Math.max(0, Math.floor(Number(opts?.pendingImageCount) || 0));
  const inputQueueCount = Math.max(0, Math.floor(Number(opts?.inputQueueCount) || 0));
  const hasLiveSpinner = !(!opts?.hasLiveSpinner);
  const hasStream = !(!opts?.hasStream);
  const hasProgress = !(!opts?.hasProgress);
  const agentCount = Math.max(0, Math.floor(Number(opts?.agentCount) || 0));
  const bottomChromeExtraRows = estimateBottomChromeExtraRows(mode, questionState, termWidth, pendingImageCount, inputQueueCount, hasLiveSpinner);
  const pinnedLiveRows = estimatePinnedLiveRows(mode, hasStream, hasProgress, agentCount, Math.max(0, Math.floor(Number(opts?.toolStreamCount) || 0)));
  const visibleBudget = estimateVisibleBlockBudget(termHeight, mode, bottomChromeExtraRows + pinnedLiveRows);
  const transcriptBlocks = (terminalMode === 'native') ? nativeTranscriptBlocksForStatic(blocks) : historyBlocksForTranscript(blocks);
  const staticBlockCount = (terminalMode === 'native') ? nativeArchiveBlockCount(transcriptBlocks, mode, visibleBudget, toolOutputExpanded, thinkingExpanded) : 0;
  const liveBlocks = (terminalMode === 'native') ? transcriptBlocks.slice(staticBlockCount) : transcriptBlocks;
  const transcriptRowCount = withContentWidthOverride(termWidth, () => buildTranscriptRows(liveBlocks, mode, toolOutputExpanded, thinkingExpanded).length);
  const fileRailOpen = !(!opts?.fileRailOpen);
  const fileRailExpanded = !(!opts?.fileRailExpanded);
  const fileRailWidth = fileRailOpen ? fileRailWidthForTerminal(termWidth, fileRailExpanded) : 0;
  const fileRailRows = fileRailOpen ? fileRailMaxRowsForTerminal(termHeight, terminalMode, fileRailExpanded) : 0;
  return { terminalMode: terminalMode, mode: mode, termWidth: termWidth, termHeight: termHeight, visibleBudget: visibleBudget, transcriptRowCount: transcriptRowCount, staticBlockCount: staticBlockCount, liveBlockCount: liveBlocks.length, fileRailWidth: fileRailWidth, fileRailRows: fileRailRows, headerRows: 1, lowerChromeRows: (mode === 'chat') ? 7 : 8 + bottomChromeExtraRows };
}

// @kern-source: app:1383
export function parseMarkdownToRows(baseKey: string, text: string, wrapWidth: number, paddingLeft: number, borderColor: string): any[] {
  const rows: any[] = [];
  const cleaned = String(text ?? '').trim();
  if (!cleaned) return rows;

  const codeWidth = contentWidth(8);
  const segments = parseMarkdownBlocks(cleaned);
  let rowIndex = 0;

  for (const segment of segments as any[]) {
    if (segment.type === 'prose') {
      const richLines = parseProseToRichLines(segment.text ?? '', wrapWidth);
      for (const richLine of richLines) {
        rows.push({
          key: `${baseKey}-rich-${rowIndex++}`,
          kind: 'rich',
          paddingLeft,
          richLine,
          borderColor,
        });
      }
      continue;
    }

    if (segment.type === 'code') {
      const codeLines = String(segment.code ?? '').split('\n');
      const shownLines = codeLines.slice(0, MAX_CODE_LINES);
      const overflow = codeLines.length - shownLines.length;
      const isDiff = segment.language === 'diff' || codeLines.some((line: string) => /^[+\-@]/.test(line));

      rows.push({
        key: `${baseKey}-code-meta-${rowIndex++}`,
        kind: 'segments',
        paddingLeft,
        borderColor,
        segments: [
          { text: CODE_RAIL, color: CODE_RAIL_COLOR },
          { text: ' ' },
          { text: segment.language || 'code', dimColor: true },
          segment.index !== undefined ? { text: ` [${segment.index}]`, color: '#585858' } : null,
        ].filter(Boolean),
      });

      shownLines.forEach((line: string, index: number) => {
        rows.push({
          key: `${baseKey}-code-${rowIndex++}-${index}`,
          kind: isDiff ? 'diff' : 'syntax',
          paddingLeft,
          borderColor,
          prefixText: `${CODE_RAIL} `,
          prefixColor: CODE_RAIL_COLOR,
          text: line,
          maxWidth: codeWidth,
        });
      });

      if (overflow > 0) {
        rows.push({
          key: `${baseKey}-code-overflow-${rowIndex++}`,
          kind: 'segments',
          paddingLeft,
          borderColor,
          segments: [
            { text: CODE_RAIL, color: CODE_RAIL_COLOR },
            { text: ' ' },
            { text: `… ${overflow} more lines`, dimColor: true },
          ],
        });
      }
      continue;
    }

    if (segment.type === 'table') {
      const headers = (segment.headers ?? []) as string[];
      const tableRows = (segment.rows ?? []) as string[][];
      const headerLine = headers.join(' │ ');
      const ruleWidth = Math.max(12, Math.min(wrapWidth, headerLine.length));

      rows.push({
        key: `${baseKey}-table-head-${rowIndex++}`,
        kind: 'segments',
        paddingLeft,
        borderColor,
        segments: [{ text: headerLine, bold: true }],
      });
      rows.push({
        key: `${baseKey}-table-rule-${rowIndex++}`,
        kind: 'segments',
        paddingLeft,
        borderColor,
        segments: [{ text: '─'.repeat(ruleWidth), dimColor: true }],
      });
      tableRows.forEach((tableRow: string[], index: number) => {
        rows.push({
          key: `${baseKey}-table-row-${rowIndex++}-${index}`,
          kind: 'segments',
          paddingLeft,
          borderColor,
          segments: [{ text: tableRow.join(' │ ') }],
        });
      });
    }
  }

  return rows;
}

// @kern-source: app:1491
export function buildToolCallRows(baseKey: string, event: any, toolOutputExpanded: boolean): any[] {
  if (!event.input && !event.output && (event.tool === 'Delegate' || event.tool === 'delegate')) return [];

  const rows: any[] = [];
  const ic = icons();
  const toolColor = event.status === 'error' ? '#ef4444' : event.status === 'done' ? '#4ade80' : '#fbbf24';
  const icon = event.status === 'error' ? ic.fail : event.status === 'done' ? ic.success : '⟳';
  const eColor = engineColor(event.engineId ?? '');
  const codeWidth = contentWidth(10);
  const { rawInput, parsed, toolKey } = parseToolCallPayload(event);
  const collapsed = !toolOutputExpanded;
  const collapsedHint: any[] = [];
  const changeOpenHint: any[] = [];
  if (event.status === 'error') {
    collapsedHint.push({ text: ' · Ctrl+Y retry', color: '#fbbf24' });
  }
  const nestSegment = { text: ' ⏿ ', color: eColor };
  const pushSegmentsRow = (suffix: string, segments: any[], paddingLeft = 2) => {
    rows.push({ key: `${baseKey}-${suffix}`, kind: 'segments', paddingLeft, segments });
  };
  const pushOpenHintRow = (suffix: string, text: string) => {
    pushSegmentsRow(suffix, [
      { text, dimColor: true },
    ]);
  };
  const pushDiffPreview = (suffix: string, lines: string[], sign: string, expanded: boolean, label: string) => {
    if (!lines.length) return;
    const window = toolPreviewWindow(lines.length, expanded);
    const headLines = lines.slice(0, window.head);
    const tailLines = window.tail > 0 ? lines.slice(-window.tail) : [];
    headLines.forEach((line: string, index: number) => {
      rows.push({
        key: `${baseKey}-${suffix}-head-${index}`,
        kind: 'diff',
        paddingLeft: 2,
        text: `${sign}${line}`,
        maxWidth: codeWidth,
      });
    });
    if (window.skipped > 0) {
      pushOpenHintRow(`${suffix}-skip`, `    … ${window.skipped} more ${label} lines`);
    }
    tailLines.forEach((line: string, index: number) => {
      rows.push({
        key: `${baseKey}-${suffix}-tail-${index}`,
        kind: 'diff',
        paddingLeft: 2,
        text: `${sign}${line}`,
        maxWidth: codeWidth,
      });
    });
  };

  if (toolKey === 'reportconfidence') {
    pushSegmentsRow('confidence', [
      { text: `▹ ${formatConfidenceToolLabel(parsed, rawInput)}`, color: '#a8a8a8', italic: true },
    ]);
    return rows;
  }

  const pushRetryHintIfNeeded = (suffix: string) => {
    if (event.status !== 'error') return;
    pushOpenHintRow(suffix, '    Ctrl+Y drafts this failed tool into the composer so you can edit and retry.');
  };

  if (toolKey === 'bash' || toolKey === 'run' || toolKey === 'agonbash') {
    const cmd = String((parsed.command as string) || rawInput || '');
    const desc = parsed.description as string | undefined;
    if (collapsed) {
      const outputLines = event.output ? String(event.output).split('\n').length : 0;
      const previewSource = desc || cmd.split('\n')[0] || '';
      const preview = previewSource.length > 60 ? `${previewSource.slice(0, 59)}…` : previewSource;
      pushSegmentsRow('bash-collapsed', [
        nestSegment,
        { text: `${icon} Bash`, color: toolColor, bold: true },
        preview ? { text: desc ? ' · ' : ' $ ', dimColor: true } : null,
        preview ? { text: preview, dimColor: true } : null,
        outputLines > 0 && event.status !== 'running' ? { text: ` → ${outputLines} lines`, dimColor: true } : null,
        ...collapsedHint,
      ].filter(Boolean));
      return rows;
    }

    pushSegmentsRow('bash-head', [
      nestSegment,
      { text: `${icon} Bash`, color: toolColor, bold: true },
      desc ? { text: ` · ${desc}`, dimColor: true } : null,
    ].filter(Boolean));
    pushRetryHintIfNeeded('bash-retry');

    const cmdLines = cmd ? cmd.split('\n') : [];
    const shownCmdLines = toolOutputExpanded ? cmdLines : cmdLines.slice(0, 3);
    shownCmdLines.forEach((line: string, index: number) => {
      pushSegmentsRow(`bash-cmd-${index}`, [
        { text: `    ${index === 0 ? '$ ' : '  '}`, dimColor: true },
        { text: truncateCodeLine(line, codeWidth) },
      ]);
    });
    if (!toolOutputExpanded && cmdLines.length > 3) {
      pushSegmentsRow('bash-cmd-more', [{ text: '      …', dimColor: true }]);
    }

    if (event.output && event.status !== 'running') {
      const outputLines = String(event.output).split('\n');
      const maxHead = outputLines.length > 80 ? 30 : 50;
      const tailCount = 5;
      const showTail = !toolOutputExpanded && outputLines.length > maxHead + tailCount;
      const headLines = toolOutputExpanded ? outputLines : outputLines.slice(0, showTail ? maxHead : outputLines.length);
      const tailLines = showTail ? outputLines.slice(-tailCount) : [];
      const skipped = outputLines.length - headLines.length - tailLines.length;

      pushSegmentsRow('bash-output-gap', [{ text: ' ', dimColor: true }]);
      headLines.forEach((line: string, index: number) => {
        if (event.status === 'error') {
          pushSegmentsRow(`bash-err-${index}`, [
            { text: '    ', dimColor: true },
            { text: truncateCodeLine(line, codeWidth), color: '#ef4444' },
          ]);
          return;
        }
        rows.push({
          key: `${baseKey}-bash-out-${index}`,
          kind: 'ansi',
          paddingLeft: 2,
          prefixText: '    ',
          prefixDimColor: true,
          text: line,
          maxWidth: codeWidth,
          fallbackDim: true,
        });
      });
      if (!toolOutputExpanded && skipped > 0) {
        pushOpenHintRow('bash-skip', `    … ${skipped} more lines …`);
      }
      tailLines.forEach((line: string, index: number) => {
        if (event.status === 'error') {
          pushSegmentsRow(`bash-tail-err-${index}`, [
            { text: '    ', dimColor: true },
            { text: truncateCodeLine(line, codeWidth), color: '#ef4444' },
          ]);
          return;
        }
        rows.push({
          key: `${baseKey}-bash-tail-${index}`,
          kind: 'ansi',
          paddingLeft: 2,
          prefixText: '    ',
          prefixDimColor: true,
          text: line,
          maxWidth: codeWidth,
          fallbackDim: true,
        });
      });
    }
    return rows;
  }

  if (toolKey === 'edit' || toolKey === 'update' || toolKey === 'agonedit') {
    const filePath = String((parsed.file_path as string) || (parsed.filePath as string) || '');
    const oldStr = String((parsed.old_string as string) || (parsed.oldString as string) || '');
    const newStr = String((parsed.new_string as string) || (parsed.newString as string) || '');
    const shortPath = filePath ? shortToolPath(filePath) : '';
    const oldLines = oldStr ? oldStr.split('\n') : [];
    const newLines = newStr ? newStr.split('\n') : [];

    pushSegmentsRow('edit-head', [
      nestSegment,
      { text: `${icon} ${ic.edit} Update`, color: toolColor, bold: true },
      shortPath ? { text: ` (${shortPath})`, color: '#a78bfa' } : null,
      { text: ' · ', dimColor: true },
      { text: `-${oldLines.length}`, color: '#ef4444' },
      { text: ' ', dimColor: true },
      { text: `+${newLines.length}`, color: '#4ade80' },
      { text: ' lines', dimColor: true },
      ...changeOpenHint,
      ...collapsedHint,
    ].filter(Boolean));
    pushDiffPreview('edit-old', oldLines, '-', !collapsed, 'removed');
    pushDiffPreview('edit-new', newLines, '+', !collapsed, 'added');
    return rows;
  }

  if (toolKey === 'write' || toolKey === 'agonwrite') {
    const filePath = String((parsed.file_path as string) || (parsed.filePath as string) || '');
    const content = String((parsed.content as string) || '');
    const shortPath = filePath ? shortToolPath(filePath) : '';
    const lines = content ? content.split('\n') : [];

    pushSegmentsRow('write-head', [
      nestSegment,
      { text: `${icon} ${ic.write} Write`, color: toolColor, bold: true },
      shortPath ? { text: ` (${shortPath})`, color: '#a78bfa' } : null,
      lines.length > 0 ? { text: ' · ', dimColor: true } : null,
      lines.length > 0 ? { text: `+${lines.length}`, color: '#4ade80' } : null,
      lines.length > 0 ? { text: ' lines', dimColor: true } : null,
      ...changeOpenHint,
      ...collapsedHint,
    ].filter(Boolean));
    pushDiffPreview('write', lines, '+', !collapsed, 'added');
    return rows;
  }

  if (toolKey === 'applypatch' || toolKey === 'apply_patch') {
    const patch = parsePatchPreview(rawInput, parsed);
    const fileSummary = patch.files.length > 0
      ? ` (${patch.files.slice(0, 2).map((filePath: string) => shortToolPath(filePath)).join(', ')}${patch.files.length > 2 ? ', …' : ''})`
      : '';

    pushSegmentsRow('patch-head', [
      nestSegment,
      { text: `${icon} ${ic.edit} Patch`, color: toolColor, bold: true },
      fileSummary ? { text: fileSummary, color: '#a78bfa' } : null,
      { text: ' · ', dimColor: true },
      { text: `-${patch.deletions}`, color: '#ef4444' },
      { text: ' ', dimColor: true },
      { text: `+${patch.additions}`, color: '#4ade80' },
      { text: ' lines', dimColor: true },
      ...changeOpenHint,
      ...collapsedHint,
    ].filter(Boolean));
    pushDiffPreview('patch', patch.lines, '', !collapsed, 'changed');
    return rows;
  }

  if (toolKey === 'read') {
    const filePath = String((parsed.file_path as string) || (parsed.filePath as string) || '');
    const shortPath = filePath ? shortToolPath(filePath) : '';
    const lineCount = event.output ? String(event.output).split('\n').length : 0;
    if (collapsed) {
      pushSegmentsRow('read-collapsed', [
        nestSegment,
        { text: `${icon} ${ic.read} Read`, color: toolColor, bold: true },
        shortPath ? { text: ` (${shortPath})`, color: '#a78bfa' } : null,
        lineCount > 0 && event.status === 'done' ? { text: ` ${lineCount} lines`, dimColor: true } : null,
        ...collapsedHint,
      ].filter(Boolean));
      return rows;
    }

    pushSegmentsRow('read-head', [
      nestSegment,
      { text: `${icon} ${ic.read} Read`, color: toolColor, bold: true },
      shortPath ? { text: ` (${shortPath})`, color: '#a78bfa' } : null,
      lineCount > 0 && event.status === 'done' ? { text: ` · ${lineCount} lines`, dimColor: true } : null,
    ].filter(Boolean));

    if (event.output && event.status !== 'running') {
      const outputLines = String(event.output).split('\n');
      const shownLines = outputLines;
      shownLines.forEach((line: string, index: number) => {
        rows.push({
          key: `${baseKey}-read-${index}`,
          kind: 'syntax',
          paddingLeft: 2,
          prefixText: '    ',
          prefixDimColor: true,
          text: line,
          maxWidth: codeWidth,
        });
      });
      if (outputLines.length > shownLines.length) {
        pushOpenHintRow('read-more', `    … ${outputLines.length - shownLines.length} more lines`);
      }
    }
    return rows;
  }

  if (toolKey === 'grep' || toolKey === 'search') {
    const pattern = String((parsed.pattern as string) || rawInput || '');
    const path = String((parsed.path as string) || '');
    const shortPath = path ? shortToolPath(path) : '';
    const matchCount = event.output ? String(event.output).split('\n').filter((line: string) => line.trim()).length : 0;
    if (collapsed) {
      pushSegmentsRow('search-collapsed', [
        nestSegment,
        { text: `${icon} ${ic.search} Search`, color: toolColor, bold: true },
        pattern ? { text: ` ${pattern}`, color: '#a78bfa' } : null,
        matchCount > 0 && event.status === 'done' ? { text: ` → ${matchCount} matches`, dimColor: true } : null,
        ...collapsedHint,
      ].filter(Boolean));
      return rows;
    }

    pushSegmentsRow('search-head', [
      nestSegment,
      { text: `${icon} ${ic.search} Search`, color: toolColor, bold: true },
      pattern ? { text: ` ${pattern}`, color: '#a78bfa' } : null,
      shortPath ? { text: ` in ${shortPath}`, dimColor: true } : null,
      matchCount > 0 && event.status === 'done' ? { text: ` → ${matchCount} matches`, dimColor: true } : null,
    ].filter(Boolean));

    if (event.output && event.status !== 'running') {
      const matchLines = String(event.output).split('\n').filter((line: string) => line.trim());
      const shownLines = matchLines;
      shownLines.forEach((line: string, index: number) => {
        rows.push({
          key: `${baseKey}-search-${index}`,
          kind: 'ansi',
          paddingLeft: 2,
          prefixText: '    ',
          prefixDimColor: true,
          text: line,
          maxWidth: codeWidth,
          fallbackDim: true,
        });
      });
      if (matchLines.length > shownLines.length) {
        pushOpenHintRow('search-more', `    … ${matchLines.length - shownLines.length} more matches`);
      }
    }
    return rows;
  }

  if (toolKey === 'glob' || toolKey === 'find') {
    const pattern = String((parsed.pattern as string) || rawInput || '');
    const fileCount = event.output ? String(event.output).split('\n').filter((line: string) => line.trim()).length : 0;
    if (collapsed) {
      pushSegmentsRow('find-collapsed', [
        nestSegment,
        { text: `${icon} ${ic.find} Find`, color: toolColor, bold: true },
        pattern ? { text: ` ${pattern}`, color: '#a78bfa' } : null,
        fileCount > 0 && event.status === 'done' ? { text: ` → ${fileCount} files`, dimColor: true } : null,
        ...collapsedHint,
      ].filter(Boolean));
      return rows;
    }

    pushSegmentsRow('find-head', [
      nestSegment,
      { text: `${icon} ${ic.find} Find`, color: toolColor, bold: true },
      pattern ? { text: ` ${pattern}`, color: '#a78bfa' } : null,
      fileCount > 0 && event.status === 'done' ? { text: ` → ${fileCount} files`, dimColor: true } : null,
    ].filter(Boolean));

    if (event.output && event.status !== 'running') {
      const files = String(event.output).split('\n').filter((line: string) => line.trim());
      const shownFiles = files;
      shownFiles.forEach((file: string, index: number) => {
        pushSegmentsRow(`find-file-${index}`, [{ text: `    ${truncateCodeLine(file, codeWidth)}`, dimColor: true }]);
      });
      if (files.length > shownFiles.length) {
        pushOpenHintRow('find-more', `    … ${files.length - shownFiles.length} more files`);
      }
    }
    return rows;
  }

  const label = (() => {
    if (event.tool === 'Read') return `${ic.read} Read`;
    if (event.tool === 'Edit') return `${ic.edit} Edit`;
    if (event.tool === 'Write') return `${ic.write} Write`;
    if (event.tool === 'Bash') return `${ic.bash} Bash`;
    if (event.tool === 'Grep') return `${ic.search} Search`;
    if (event.tool === 'Glob') return `${ic.find} Find`;
    return `${ic.tool} ${event.tool}`;
  })();
  const inputPreview = rawInput.length > 80 ? `${rawInput.slice(0, 79)}…` : rawInput;
  const outLines = event.output ? String(event.output).split('\n').length : 0;

  pushSegmentsRow('generic', [
    nestSegment,
    { text: `${icon} ${label}`, color: toolColor, bold: true },
    inputPreview ? { text: ` ${inputPreview}`, dimColor: true } : null,
    outLines > 0 && event.status === 'done' ? { text: ` → ${outLines} lines`, dimColor: true } : null,
    ...(collapsed ? collapsedHint : []),
  ].filter(Boolean));

  return rows;
}

// @kern-source: app:1862
export function buildCollapsedToolGroupRows(baseKey: string, events: any[]): any[] {
  if (!events || events.length === 0) return [];

  const rows: any[] = [];
  const counts = new Map<string, number>();
  const changedFiles: string[] = [];
  const changeEvents: any[] = [];
  let confidenceLabel = '';
  let errors = 0;
  let running = 0;

  const labelFor = (event: any) => {
    const toolKey = String(event.tool ?? '').toLowerCase();
    if (toolKey === 'bash' || toolKey === 'run' || toolKey === 'agonbash') return 'Bash';
    if (toolKey === 'read') return 'Read';
    if (toolKey === 'grep' || toolKey === 'search') return 'Search';
    if (toolKey === 'glob' || toolKey === 'find') return 'Find';
    if (toolKey === 'edit' || toolKey === 'update' || toolKey === 'agonedit') return 'Update';
    if (toolKey === 'write' || toolKey === 'agonwrite') return 'Write';
    if (toolKey === 'applypatch' || toolKey === 'apply_patch') return 'Patch';
    if (toolKey === 'reportconfidence') return 'Confidence';
    if (toolKey === 'quicknero') return 'QuickNero';
    return String(event.tool ?? 'Tool');
  };

  for (const event of events) {
    const { rawInput, parsed, toolKey } = parseToolCallPayload(event);
    if (event.status === 'error') errors += 1;
    if (event.status === 'running') running += 1;
    if (toolKey === 'reportconfidence') {
      confidenceLabel = formatConfidenceToolLabel(parsed, rawInput);
      continue;
    }
    const label = labelFor(event);
    counts.set(label, (counts.get(label) ?? 0) + 1);
    if (isMutatingToolCall(event)) {
      changeEvents.push(event);
      const filePath = String((parsed.file_path as string) || (parsed.filePath as string) || '');
      if (filePath) {
        const shortPath = shortToolPath(filePath);
        if (!changedFiles.includes(shortPath)) changedFiles.push(shortPath);
      }
      if (toolKey === 'applypatch' || toolKey === 'apply_patch') {
        for (const patchFile of parsePatchPreview(rawInput, parsed).files) {
          const shortPath = shortToolPath(patchFile);
          if (!changedFiles.includes(shortPath)) changedFiles.push(shortPath);
        }
      }
    }
  }

  const countSummary = Array.from(counts.entries())
    .map(([label, count]) => `${label}${count > 1 ? `×${count}` : ''}`)
    .join(' · ');
  const statusSummary = errors > 0
    ? ` · ${errors} error${errors === 1 ? '' : 's'}`
    : running > 0 ? ' · running' : '';
  const changedSummary = changedFiles.length > 0
    ? ` · changed ${changedFiles.length} file${changedFiles.length > 1 ? 's' : ''}: ${changedFiles.slice(0, 2).join(', ')}${changedFiles.length > 2 ? ', …' : ''}`
    : '';

  if (confidenceLabel) {
    rows.push({
      key: `${baseKey}-confidence`,
      kind: 'segments',
      paddingLeft: 2,
      segments: [
        { text: `▹ ${confidenceLabel}`, color: '#a8a8a8', italic: true },
      ],
    });
  }

  rows.push({
    key: `${baseKey}-tool-group-head`,
    kind: 'segments',
    paddingLeft: 4,
    segments: [
      { text: `${events.length} tool calls`, dimColor: true },
      countSummary ? { text: ' · ', dimColor: true } : null,
      countSummary ? { text: countSummary, dimColor: true } : null,
      statusSummary ? { text: statusSummary, dimColor: true } : null,
      changedSummary ? { text: changedSummary, dimColor: true } : null,
      { text: '  ' },
      { text: 'Ctrl+E', color: '#f59e0b' },
    ].filter(Boolean),
  });

  changeEvents.forEach((event: any, index: number) => {
    rows.push(...buildToolCallRows(`${baseKey}-change-${index}`, event, false));
  });

  return rows;
}

// @kern-source: app:1957
export function buildTranscriptRows(blocks: OutputBlock[], mode: string, toolOutputExpanded: boolean, thinkingExpanded: boolean): any[] {
  const rows: any[] = [];
  const proseWidth = contentWidth(4);
  const chatWidth = contentWidth(2);
  const engineWidth = contentWidth(8);
  const pushSpacer = (key: string) => {
    rows.push({ key, kind: 'spacer' });
  };
  const pushSegmentsRow = (key: string, paddingLeft: number, segments: any[], borderColor = '') => {
    rows.push({ key, kind: 'segments', paddingLeft, segments, borderColor });
  };
  const pushRichText = (baseKey: string, text: string, paddingLeft: number, wrapWidth: number, borderColor = '') => {
    const richLines = parseProseToRichLines(String(text ?? ''), wrapWidth);
    richLines.forEach((richLine: any, index: number) => {
      rows.push({
        key: `${baseKey}-rich-${index}`,
        kind: 'rich',
        paddingLeft,
        richLine,
        borderColor,
      });
    });
  };

  let skippedUntil = -1;
  blocks.forEach((block: OutputBlock, blockIndex: number) => {
    if (blockIndex < skippedUntil) return;
    const event = block.event as any;
    const baseKey = `block-${block.id}`;

    if (!toolOutputExpanded && event.type === 'tool-call') {
      const groupedEvents = [event];
      let nextIndex = blockIndex + 1;
      while (nextIndex < blocks.length) {
        const nextEvent = blocks[nextIndex].event as any;
        if (nextEvent.type !== 'tool-call') break;
        groupedEvents.push(nextEvent);
        nextIndex += 1;
      }

      if (groupedEvents.length > 1) {
        rows.push(...buildCollapsedToolGroupRows(baseKey, groupedEvents));
        skippedUntil = nextIndex;
        return;
      }
    }

    switch (event.type) {
      case 'text':
        pushRichText(baseKey, event.content, 2, proseWidth);
        return;
      case 'user-message':
        if (rows.length > 0) pushSpacer(`${baseKey}-gap`);
        pushSegmentsRow(`${baseKey}-user`, 1, [
          { text: '❯ ', color: '#f97316', bold: true },
          { text: event.content, bold: true },
        ]);
        return;
      case 'engine-block': {
        const cleaned = cleanEngineOutput(event.content);
        if (!cleaned.trim()) return;
        const accentColor = color256toHex(event.color ?? (ENGINE_COLORS[event.engineId] ?? 124));
        if (rows.length > 0) pushSpacer(`${baseKey}-gap`);
        if (mode === 'chat') {
          pushSegmentsRow(`${baseKey}-chat-head`, 1, [{ text: `${icons().dotOn} ${event.engineId}`, color: accentColor, bold: true }]);
          pushSpacer(`${baseKey}-chat-space`);
          rows.push(...parseMarkdownToRows(baseKey, cleaned, chatWidth, 1, ''));
          return;
        }
        pushSegmentsRow(`${baseKey}-engine-head`, 2, [
          { text: '┌── ', color: accentColor },
          { text: event.engineId, color: accentColor, bold: true },
        ]);
        pushSegmentsRow(`${baseKey}-engine-rule`, 2, [{ text: '│', color: accentColor }]);
        rows.push(...parseMarkdownToRows(baseKey, cleaned, engineWidth, 2, accentColor));
        pushSegmentsRow(`${baseKey}-engine-foot`, 2, [{ text: '└──', color: accentColor }]);
        return;
      }
      case 'separator':
        pushSpacer(`${baseKey}-separator`);
        return;
      case 'header':
        pushSpacer(`${baseKey}-header-gap`);
        pushSegmentsRow(`${baseKey}-header`, 0, [
          { text: '  ', dimColor: true },
          { text: `${icons().header} ${event.title}`, color: 'cyan', bold: true },
        ]);
        return;
      case 'success':
        pushSegmentsRow(`${baseKey}-success`, 0, [
          { text: '  ' },
          { text: icons().success, color: '#4ade80' },
          { text: ` ${event.message}` },
        ]);
        return;
      case 'warning':
        pushSegmentsRow(`${baseKey}-warning`, 0, [
          { text: '  ' },
          { text: icons().warning, color: '#fbbf24' },
          { text: ` ${event.message}` },
        ]);
        return;
      case 'info':
        pushSegmentsRow(`${baseKey}-info`, 0, [{
          text: `  ${event.message}`,
          dimColor: true,
          italic: isCesarTelemetryLine(String(event.message ?? '')),
          color: isCesarTelemetryLine(String(event.message ?? '')) ? '#8b8b8b' : undefined,
        }]);
        return;
      case 'error': {
        const errLines = String(event.message ?? '').split('\n');
        const firstLine = errLines[0] || 'Error';
        pushSegmentsRow(`${baseKey}-error-main`, 0, [
          { text: '  ' },
          { text: icons().fail, color: '#ef4444' },
          { text: ` ${firstLine}`, color: '#ef4444' },
        ]);
        errLines.slice(1, 5).forEach((line: string, index: number) => {
          pushSegmentsRow(`${baseKey}-error-${index}`, 0, [{ text: `    ${line.trim()}`, dimColor: true }]);
        });
        if (errLines.length > 5) {
          pushSegmentsRow(`${baseKey}-error-more`, 0, [{ text: `    … ${errLines.length - 5} more lines`, dimColor: true }]);
        }
        return;
      }
      case 'permission-ask': {
        const preview = truncateCodeLine(String(event.command ?? '').split('\n')[0] ?? '', contentWidth(26));
        const previewEvent = {
          type: 'tool-call',
          engineId: 'cesar',
          tool: event.tool,
          input: String(event.command ?? ''),
          status: 'running',
        } as any;
        pushSegmentsRow(`${baseKey}-perm-head`, 1, [
          { text: icons().warning, color: '#fbbf24' },
          { text: ` ${event.tool} approval requested`, color: '#fbbf24', bold: true },
        ]);
        pushSegmentsRow(`${baseKey}-perm-actions`, 1, [
          { text: '  [Y] Yes', color: '#4ade80', bold: true },
          { text: '  ', dimColor: true },
          { text: '[N] No', color: '#ef4444', bold: true },
          { text: '  ', dimColor: true },
          { text: '[A] Always', color: '#60a5fa', bold: true },
        ].filter(Boolean));
        pushSegmentsRow(`${baseKey}-perm-cmd`, 1, preview
          ? [
              { text: '  $ ', dimColor: true },
              { text: preview, dimColor: true },
            ]
          : [{ text: '  respond below', dimColor: true }]);
        if (isMutatingToolCall(previewEvent)) {
          rows.push(...buildToolCallRows(`${baseKey}-perm-diff`, previewEvent, false));
        }
        return;
      }
      case 'thinking-chunk': {
        if (thinkingExpanded === false) return;
        const lines = String(event.chunk ?? '').split('\n').filter((line: string) => line.trim());
        lines.forEach((line: string, index: number) => {
          pushSegmentsRow(`${baseKey}-thinking-${index}`, 2, [{ text: `▹ ${line}`, color: '#a8a8a8', italic: true }]);
        });
        return;
      }
      case 'streaming-chunk': {
        const chunkText = String(event.chunk ?? '');
        const isThinking = /^~?\d{1,3}%\s/.test(chunkText.trim());
        if (isThinking && thinkingExpanded === false) return;
        pushSegmentsRow(`${baseKey}-stream`, 2, [{ text: chunkText, dimColor: isThinking, italic: isThinking }]);
        return;
      }
      case 'kern-draft': {
        const borderColor = engineColor(event.engineId);
        if (rows.length > 0) pushSpacer(`${baseKey}-gap`);
        pushSegmentsRow(`${baseKey}-draft-head`, 2, [
          { text: '┌── ', color: borderColor },
          { text: event.engineId, color: borderColor, bold: true },
          event.critique ? { text: ` ${event.critique}`, color: 'green' } : null,
        ].filter(Boolean));
        pushSegmentsRow(`${baseKey}-draft-rule`, 2, [{ text: '│', color: borderColor }]);
        rows.push(...parseMarkdownToRows(baseKey, cleanEngineOutput(event.content), engineWidth, 2, borderColor));
        pushSegmentsRow(`${baseKey}-draft-foot`, 2, [{ text: '└──', color: borderColor }]);
        return;
      }
      case 'debate-round': {
        const borderColor = engineColor(event.engineId);
        if (rows.length > 0) pushSpacer(`${baseKey}-gap`);
        pushSegmentsRow(`${baseKey}-debate-head`, 2, [
          { text: '┌── ', color: borderColor },
          { text: event.engineId, color: borderColor, bold: true },
          { text: ` (${event.position})`, dimColor: true },
        ]);
        pushSegmentsRow(`${baseKey}-debate-rule`, 2, [{ text: '│', color: borderColor }]);
        rows.push(...parseMarkdownToRows(baseKey, cleanEngineOutput(event.argument), engineWidth, 2, borderColor));
        pushSegmentsRow(`${baseKey}-debate-foot`, 2, [{ text: '└──', color: borderColor }]);
        return;
      }
      case 'verdict':
        pushRichText(baseKey, cleanEngineOutput(event.summary), 2, proseWidth);
        return;
      case 'scoreboard':
        pushSegmentsRow(`${baseKey}-score-title`, 2, [{ text: event.title, bold: true }]);
        if (event.winner) pushSegmentsRow(`${baseKey}-score-winner`, 2, [{ text: `★ Winner: ${event.winner}`, color: 'green', bold: true }]);
        pushSegmentsRow(`${baseKey}-score-rule`, 2, [{ text: '─'.repeat(46), dimColor: true }]);
        (event.metrics ?? []).forEach((metric: any, index: number) => {
          pushSegmentsRow(`${baseKey}-score-${index}`, 2, [{ text: `${metric.label}: ${metric.values.join(' │ ')}` }]);
        });
        return;
      case 'plan':
        pushSegmentsRow(`${baseKey}-plan-id`, 2, [{ text: `▸ Plan: ${event.plan.id.slice(0, 12)}`, color: 'cyan', bold: true }]);
        pushSegmentsRow(`${baseKey}-plan-state`, 2, [{ text: `State: ${event.plan.state}` }]);
        pushSegmentsRow(`${baseKey}-plan-task`, 2, [{ text: `Task: ${event.plan.action.task}` }]);
        pushSegmentsRow(`${baseKey}-plan-rule`, 2, [{ text: '─'.repeat(46), dimColor: true }]);
        (event.plan.steps ?? []).forEach((step: any, index: number) => {
          const state = step.result?.state ?? 'pending';
          const icon = state === 'completed' ? icons().success : state === 'failed' ? icons().fail : state === 'running' ? icons().dotOn : icons().dotOff;
          const color = state === 'completed' ? 'green' : state === 'failed' ? 'red' : state === 'running' ? 'yellow' : undefined;
          pushSegmentsRow(`${baseKey}-plan-step-${index}`, 2, [
            { text: icon, color },
            { text: ` ${step.label}` },
          ]);
        });
        if (event.plan.state === 'draft') {
          pushSegmentsRow(`${baseKey}-plan-draft`, 2, [{ text: 'Awaiting approval — Y accept  N cancel', dimColor: true }]);
        }
        return;
      case 'plan-list':
        (event.plans ?? []).forEach((plan: any, index: number) => {
          pushSegmentsRow(`${baseKey}-plan-list-${index}`, 2, [{ text: `${plan.id.slice(0, 12)}  ${plan.state}  ${plan.action.task}` }]);
        });
        return;
      case 'plan-proposal':
        pushRichText(baseKey, String(event.markdown ?? ''), 2, proseWidth);
        return;
      case 'plan-execution':
        pushSegmentsRow(`${baseKey}-plan-exec`, 2, [{ text: `Executing plan ${event.plan?.id?.slice?.(0, 12) ?? ''}`, bold: true }]);
        pushSegmentsRow(`${baseKey}-plan-exec-state`, 2, [{ text: `State: ${event.plan?.state ?? 'running'}`, dimColor: true }]);
        return;
      case 'table': {
        pushSegmentsRow(`${baseKey}-table-head`, 2, [{ text: (event.headers ?? []).join(' │ '), bold: true }]);
        pushSegmentsRow(`${baseKey}-table-rule`, 2, [{ text: '─'.repeat(Math.max(12, (event.headers ?? []).join(' │ ').length)), dimColor: true }]);
        (event.rows ?? []).forEach((row: string[], index: number) => {
          pushSegmentsRow(`${baseKey}-table-row-${index}`, 2, [{ text: row.join(' │ ') }]);
        });
        return;
      }
      case 'tool-call':
        rows.push(...buildToolCallRows(baseKey, event, toolOutputExpanded));
        return;
      case 'tool-call-group': {
        const groupBlocks = Array.isArray((event as any).blocks) ? (event as any).blocks : [];
        // Expanded: unpack every inner tool call so Ctrl+E reveals full
        // output. Collapsed (default): one compact summary row, matching
        // the Static-era ToolCallGroup renderer — preserves the bundling
        // that output.kern emits (codex review P3).
        if (toolOutputExpanded) {
          groupBlocks.forEach((child: any, index: number) => {
            const childEvent = child?.event;
            if (childEvent && childEvent.type === 'tool-call') {
              rows.push(...buildToolCallRows(`${baseKey}-g-${index}`, childEvent, toolOutputExpanded));
            }
          });
          return;
        }
        const groupedEvents: any[] = [];
        const appendGroup = (blocksToAppend: any[]) => {
          blocksToAppend.forEach((child: any) => {
            const childEvent = child?.event;
            if (childEvent && childEvent.type === 'tool-call') groupedEvents.push(childEvent);
          });
        };
        appendGroup(groupBlocks);
        let nextIndex = blockIndex + 1;
        while (nextIndex < blocks.length) {
          const nextEvent = blocks[nextIndex].event as any;
          if (nextEvent?.type === 'tool-call-group') {
            appendGroup(Array.isArray(nextEvent.blocks) ? nextEvent.blocks : []);
            nextIndex += 1;
            continue;
          }
          if (nextEvent?.type === 'tool-call') {
            groupedEvents.push(nextEvent);
            nextIndex += 1;
            continue;
          }
          break;
        }
        rows.push(...buildCollapsedToolGroupRows(baseKey, groupedEvents));
        skippedUntil = nextIndex;
        return;
      }
      case 'response-meta': {
        const totalTokens = (event.inputTokens ?? 0) + (event.outputTokens ?? 0);
        const parts = [
          event.engineId,
          `${(event.elapsed / 1000).toFixed(1)}s`,
          totalTokens > 0 ? `${totalTokens} tok` : '',
          event.cost ? `$${event.cost.toFixed(4)}` : '',
        ].filter(Boolean);
        pushSegmentsRow(`${baseKey}-meta`, 2, [{ text: parts.join(' · '), dimColor: true }]);
        return;
      }
      case 'cesar-recap': {
        const files = Array.isArray((event as any).files) ? (event as any).files : [];
        const commands = Array.isArray((event as any).commands) ? (event as any).commands : [];
        const warnings = Array.isArray((event as any).warnings) ? (event as any).warnings : [];
        const toolSummary = Array.isArray((event as any).toolSummary) ? (event as any).toolSummary : [];
        const checkpoints = Array.isArray((event as any).checkpoints) ? (event as any).checkpoints : [];
        const diffFiles = Array.isArray((event as any).diffPreview?.files) ? (event as any).diffPreview.files : [];
        const confidence = typeof (event as any).confidence === 'number' ? `${Math.round((event as any).confidence)}% confidence` : '';
        const seconds = typeof (event as any).durationMs === 'number' ? `${(((event as any).durationMs) / 1000).toFixed(1)}s` : '';
        const failedTools = Number((event as any).failedTools ?? 0);
        const statusIcon = failedTools > 0 ? icons().warning : icons().success;
        const statusColor = failedTools > 0 ? '#fbbf24' : '#4ade80';
        const toolLine = toolSummary.length > 0
          ? `${(event as any).toolCount ?? toolSummary.length} tools: ${toolSummary.slice(0, 8).join(', ')}${toolSummary.length > 8 ? ', ...' : ''}`
          : `${(event as any).toolCount ?? 0} tools`;
        const fileGlyph = (status: string) => status === 'edited' ? 'M' : status === 'created' ? '+' : 'r';
        pushSegmentsRow(`${baseKey}-recap-head`, 1, [{ text: '◆ Cesar recap', color: '#f97316', bold: true }]);
        pushSegmentsRow(`${baseKey}-recap-outcome`, 1, [
          { text: statusIcon, color: statusColor },
          { text: ` ${(event as any).outcome ?? 'Completed'}` },
          { text: ` · ${(event as any).mode ?? 'self'}`, dimColor: true },
          confidence ? { text: ` · ${confidence}`, dimColor: true } : null,
          seconds ? { text: ` · ${seconds}`, dimColor: true } : null,
        ].filter(Boolean));
        pushSegmentsRow(`${baseKey}-recap-tools`, 1, [{ text: `  ${toolLine}${failedTools > 0 ? ` · ${failedTools} failed` : ''}`, dimColor: true }]);
        if ((event as any).confidenceReasoning) {
          pushSegmentsRow(`${baseKey}-recap-why`, 1, [{ text: `  why: ${(event as any).confidenceReasoning}`, italic: true, color: '#a8a8a8' }]);
        }
        commands.slice(0, 5).forEach((cmd: any, index: number) => {
          const failed = String(cmd.status).toLowerCase() === 'error';
          pushSegmentsRow(`${baseKey}-recap-cmd-${index}`, 1, [
            { text: `  ${failed ? icons().fail : icons().success}`, color: failed ? '#ef4444' : '#4ade80' },
            { text: ` ${cmd.label}` },
            { text: ` · ${cmd.command}`, dimColor: true },
          ]);
        });
        if (files.length > 0) {
          pushSegmentsRow(`${baseKey}-recap-files`, 1, [{
            text: `  files: ${files.slice(0, 5).map((f: any) => `${fileGlyph(String(f.status))} ${f.relPath ?? f.path}`).join(', ')}${files.length > 5 ? `, +${files.length - 5} more` : ''}`,
            dimColor: true,
          }]);
        }
        if (checkpoints.length > 0) {
          pushSegmentsRow(`${baseKey}-recap-checkpoint`, 1, [{
            text: `  checkpoint: ${checkpoints[0].id}${checkpoints.length > 1 ? ` (+${checkpoints.length - 1})` : ''} · /undo ${checkpoints[0].id} reverts checkpoint`,
            color: '#22d3ee',
          }]);
        }
        diffFiles.slice(0, 4).forEach((file: any, index: number) => {
          pushSegmentsRow(`${baseKey}-recap-diff-${index}`, 1, [
            { text: `  Δ ${file.relPath ?? file.path}`, color: '#22d3ee' },
            { text: ` +${Number(file.additions ?? 0)} -${Number(file.deletions ?? 0)}`, dimColor: true },
          ]);
          const lines = Array.isArray(file.lines) ? file.lines : [];
          lines.slice(0, 6).forEach((line: string, lineIndex: number) => {
            const color = line.startsWith('+') ? '#4ade80' : line.startsWith('-') ? '#ef4444' : '#fbbf24';
            pushSegmentsRow(`${baseKey}-recap-diff-${index}-${lineIndex}`, 1, [{
              text: `    ${line}`,
              color,
              dimColor: line.startsWith('@@'),
            }]);
          });
          if (Number(file.omitted ?? 0) > 0) {
            pushSegmentsRow(`${baseKey}-recap-diff-${index}-more`, 1, [{
              text: `    … ${Number(file.omitted)} more diff lines`,
              dimColor: true,
            }]);
          }
        });
        warnings.slice(0, 3).forEach((warning: string, index: number) => {
          pushSegmentsRow(`${baseKey}-recap-warning-${index}`, 1, [
            { text: `  ${icons().warning}`, color: '#fbbf24' },
            { text: ` ${warning}`, color: '#fbbf24' },
          ]);
        });
        return;
      }
      case 'file-changes':
        pushSegmentsRow(`${baseKey}-files-head`, 2, [{ text: 'Files changed', bold: true }]);
        (event.files ?? []).forEach((file: any, index: number) => {
          const shortPath = String(file.path ?? '').replace(`${process.cwd()}/`, '');
          pushSegmentsRow(`${baseKey}-file-${index}`, 2, [{
            text: `${file.status === 'created' ? icons().dotOn : file.status === 'deleted' ? '⊖' : icons().success} ${shortPath} +${file.additions} -${file.deletions}`,
            color: file.status === 'created' ? '#22d3ee' : file.status === 'deleted' ? '#ef4444' : '#4ade80',
          }]);
        });
        return;
      case 'dashboard':
        LOGO_LINES.forEach((line: string, index: number) => {
          rows.push({
            key: `${baseKey}-logo-${index}`,
            kind: 'gradient',
            paddingLeft: 1,
            text: line,
            colors: BRAND,
          });
        });
        pushSpacer(`${baseKey}-dash-gap-1`);
        pushSegmentsRow(`${baseKey}-dash-tag`, 0, [{ text: '     Any AI can join. They compete. You ship.', color: '#d4a041', italic: true }]);
        pushSegmentsRow(`${baseKey}-dash-version`, 0, [
          { text: `     v${VERSION}  Powered by `, dimColor: true },
          { text: 'KERNlang', color: '#fbbf24', bold: true },
        ]);
        pushSegmentsRow(`${baseKey}-dash-engines`, 0, [
          { text: '  Engines: ', color: '#f97316' },
          ...((event.enabled ?? []) as string[]).flatMap((engineId: string, index: number, list: string[]) => ([
            { text: engineId, color: engineColor(engineId), bold: true },
            index < list.length - 1 ? { text: ' ', dimColor: true } : null,
          ].filter(Boolean))),
        ].filter(Boolean));
        if (event.eloTop) {
          pushSegmentsRow(`${baseKey}-dash-elo`, 0, [
            { text: '  ' },
            { text: '♛ ', color: '#fbbf24' },
            { text: event.eloTop.id, color: engineColor(event.eloTop.id), bold: true },
            { text: ` ${event.eloTop.rating} ELO`, dimColor: true },
          ]);
        }
        [
          { prompt: '"explain the auth flow"', target: 'chat', color: '#fbbf24' },
          { prompt: '"codex how would you do this?"', target: 'codex', color: '#60a5fa' },
          { prompt: '"fix login bug, test with npm test"', target: 'forge', color: '#f97316' },
          { prompt: '"should we use REST or GraphQL?"', target: 'tribunal', color: '#a78bfa' },
        ].forEach((example: any, index: number) => pushSegmentsRow(`${baseKey}-dash-example-${index}`, 0, [
          { text: '  ', dimColor: true },
          { text: example.prompt, dimColor: true, italic: true },
          { text: '  →  ', dimColor: true },
          { text: example.target, color: example.color },
        ]));
        pushSpacer(`${baseKey}-dash-gap-4`);
        pushSegmentsRow(`${baseKey}-dash-help`, 0, [
          { text: '  Just talk, or type ', dimColor: true },
          { text: '/', color: '#f97316' },
          { text: ' for commands. ', dimColor: true },
          { text: 'Tab', color: '#f97316' },
          { text: ' plan · ', dimColor: true },
          { text: 'Ctrl+A', color: '#f97316' },
          { text: ' auto', dimColor: true },
        ]);
        return;
      case 'agent-step-start':
        pushSegmentsRow(`${baseKey}-agent-start`, 2, [{ text: `${event.engineId} turn ${event.turnIndex + 1} started`, dimColor: true }]);
        return;
      case 'agent-step-end':
        pushSegmentsRow(`${baseKey}-agent-end`, 2, [{ text: `${event.engineId} ${event.outcome} · ${event.toolCalls} tools · ${event.tokensUsed} tok`, dimColor: true }]);
        return;
      case 'agent-turn-summary':
        pushSegmentsRow(`${baseKey}-agent-summary`, 2, [{ text: `${event.engineId} summary · ${event.turnsRemaining} turns left · ${event.cumulativeTokens} tok`, dimColor: true }]);
        return;
      case 'agent-budget-warning':
        pushSegmentsRow(`${baseKey}-agent-budget`, 2, [{ text: `${event.engineId} ${event.kind} budget warning · ${event.remaining} remaining`, color: '#fbbf24' }]);
        return;
      case 'engine-switch':
        pushSegmentsRow(`${baseKey}-engine-switch`, 2, [{ text: `Engine switch: ${event.from ?? 'auto'} → ${event.to}`, dimColor: true }]);
        return;
      case 'shadow-active':
        pushSegmentsRow(`${baseKey}-shadow`, 2, [{ text: `Shadow active: ${event.shadowEngineId} behind ${event.foregroundEngineId}`, dimColor: true }]);
        return;
      case 'agent-routing':
        pushSegmentsRow(`${baseKey}-routing`, 2, [{ text: `Routing: ${event.mode} · ${event.engines.join(', ')}`, dimColor: true }]);
        return;
      case 'agent-team-start':
        pushSegmentsRow(`${baseKey}-team-start`, 2, [{ text: `Team ${event.teamId}: ${event.engineIds.join(', ')} · ${event.taskKind}`, dimColor: true }]);
        return;
      case 'agent-team-complete':
        pushSegmentsRow(`${baseKey}-team-complete`, 2, [{ text: `Team ${event.teamId} complete · winner ${event.winner ?? 'none'} · $${event.teamCostUsd.toFixed(2)}`, dimColor: true }]);
        return;
      case 'spinner-start':
      case 'spinner-stop':
      case 'spinner-update':
      case 'progress-update':
      case 'progress-clear':
      case 'confidence-update':
      case 'streaming-end':
      case 'clear':
      case 'question':
      case 'patch-review':
        return;
      default:
        pushSegmentsRow(`${baseKey}-fallback`, 2, [{ text: `[${event.type}]`, dimColor: true }]);
    }
  });

  return rows;
}

// @kern-source: app:4463
export async function startRepl(): Promise<void> {
  ensureAgonHome();
  ensureCurrentWorkspace(process.cwd());
  process.on('SIGINT', () => {
    const now = Date.now();
    if (now - _lastSigintAt.value < 1200) {
      if (_cesarSessionRef.session) { try { _cesarSessionRef.session.close(); } catch { /* session already closed or errored */ } _cesarSessionRef.session = null; }
      process.exit(0);
    }
    if (_pauseState.value?.active) {
      // Second Ctrl+C during pause — hard cancel
      _pauseState.value = dismissPauseState();
      for (const abort of _activeAborts) abort.abort();
      _activeAborts.clear();
      _lastSigintAt.value = now;
      if (_cancelCallback.fn) _cancelCallback.fn();
      return;
    }
    if (_activeAborts.size > 0) {
      // First Ctrl+C — enter pause state instead of immediate abort
      _pauseState.value = createPauseState();
      _lastSigintAt.value = now;
      return;
    }
    _lastSigintAt.value = now;
  });
  if (process.stdout.isTTY) {
    process.on('exit', () => {
      try { drainStdinBuffer(); } catch { /* stdout gone */ }
    });
  }
  render(<App />, { exitOnCtrlC: false });
}
